mapper.select:
SELECT id, user_id AS userId, session_id AS sessionId, question_message_id AS questionMessageId, answer_message_id AS answerMessageId, model_name AS modelName, CASE WHEN from_cache = 1 THEN TRUE ELSE FALSE END AS fromCache, call_status AS callStatus, duration_ms AS durationMs, prompt_tokens AS promptTokens, completion_tokens AS completionTokens, error_message AS errorMessage, created_at AS createdAt FROM model_call_log
call_status = #{callStatus}
ORDER BY created_at DESC, id DESC LIMIT #{pageSize} OFFSET #{offset}
